jobEntity.trigger(["update.job_status"], async (whatWas, whatIs, job) => {
  if (whatWas.job_status === whatIs.job_status) return

  const host = await UserService.getUserById(job.host_id)
  if (!host?.email) return

  await Mail.sendOne(
    host.email,
    `Job updated - ${whatIs.job_status}`,
    buildEmail(host.firstName, job.title_name, whatIs.job_status)
  )
})

settingsEntity.trigger(["update.extra_data[tokenName].Zugacoin"], (whatWas, whatIs, setting) => {
  console.log("Zugacoin config changed", { from: whatWas.extra_data, to: whatIs.extra_data })
})

booksEntity.trigger(["create", "update"], (_ww, _wi, book) => {
  searchIndex.upsert(book.uuid, {
    title: book.title_name,
    description: book.description
  })
})

booksEntity.trigger(["delete"], (whatWas, _wi, book) => {
  AuditLog.record({
    action: "delete",
    entity: "books",
    entityId: book.uuid,
    snapshot: whatWas
  })
})

booksEntity.intercept("delete", (req, res, next) => {
  if (!req.user?.isAdmin) {
    return res.status(403).json({ message: "Forbidden" })
  }
  next()
})

booksEntity.intercept("read", (req, res, next) => {
  req.query["filter[owned_by]"] = req.user.uuid
  next()
})

booksEntity.intercept(["create", "update"], (req, res, next) => {
  req.body.updated_by = req.user?.uuid
  next()
})

booksEntity.intercept("all", (req, res, next) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.originalUrl}`)
  next()
})

