const chaptersEntity = new MetaEntity("chapters", {
  parents: [{
    entity: () => booksEntity,
    type: "parent",
    foreignKey: "bookId"
  }]
});

// bookId is now required on create
await chaptersEntity.service.create({
  title_name: "Chapter One",
  chapterNumber: 1,
  bookId: book.uuid
});

const booksEntity = new MetaEntity("books", {
  children: [{
    entity: () => chaptersEntity,
    foreignKey: "bookId",
    alias: "chapters"
  }]
});

// Fetch book with paginated chapters
const book = await booksEntity.service.withChildren(id, {
  includeChildren: ["chapters"],
  childPagination: {
    chapters: { page: 1, limit: 10 }
  }
});

const profileEntity = new MetaEntity("profiles", {
  sisters: [{
    entity: () => userEntity,
    type: "sister",
    foreignKey: "userId"
  }]
});

// userId is required on create
await profileEntity.service.create({
  bio: "Developer",
  userId: user.uuid
});

